import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"随机图像 API 与访客图库","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/random-image-api-and-public-gallery.md","filePath":"cn/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),o={name:"cn/Other/random-image-api-and-public-gallery.md"};function i(s,t,c,p,n,h){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="随机图像-api-与访客图库" tabindex="-1">随机图像 API 与访客图库 <a class="header-anchor" href="#随机图像-api-与访客图库" aria-label="Permalink to &quot;随机图像 API 与访客图库&quot;">​</a></h1><p>这两个功能都在：</p><p>系统配置 -&gt; 其他设置</p><h2 id="随机图像-api" tabindex="-1">随机图像 API <a class="header-anchor" href="#随机图像-api" aria-label="Permalink to &quot;随机图像 API&quot;">​</a></h2><p>随机图像 API 用来从指定目录里随机取出一个文件，适合做站点背景图、头像轮播、外部页面随机图片调用。</p><p>开启后可以访问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/random</span></span></code></pre></div><h2 id="随机图像-api-设置" tabindex="-1">随机图像 API 设置 <a class="header-anchor" href="#随机图像-api-设置" aria-label="Permalink to &quot;随机图像 API 设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>作用</th></tr></thead><tbody><tr><td>启用</td><td>开启或关闭 <code>/random</code> 接口。关闭时访问会返回禁止访问。</td></tr><tr><td>目录</td><td>限制随机接口可以从哪些目录取文件。未包含在这里的目录不能被随机接口调用。</td></tr><tr><td>调用演示</td><td>帮你生成随机图接口链接，可直接复制使用。</td></tr></tbody></table><p>目录可以选择多个。比如只允许 <code>/landscape/</code> 和 <code>/portrait/</code>，随机接口就只能从这两个目录或它们的子目录里取文件。</p><h2 id="随机图像-api-参数" tabindex="-1">随机图像 API 参数 <a class="header-anchor" href="#随机图像-api-参数" aria-label="Permalink to &quot;随机图像 API 参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>示例</th><th>作用</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>指定随机目录。</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>指定媒体类型，可用 <code>image</code>、<code>video</code>、<code>audio</code>，也可用逗号组合。</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>图片方向筛选，可用 <code>portrait</code>、<code>landscape</code>、<code>auto</code>。</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>返回格式。留空为跳转，<code>url</code> 返回纯链接，<code>json</code> 返回 JSON 数据。</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>配合 <code>type=url</code> 使用，返回完整链接。</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>年龄分级筛选。</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>只随机包含这些标签的文件。</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>排除包含这些标签的文件。</td></tr></tbody></table><h2 id="返回格式" tabindex="-1">返回格式 <a class="header-anchor" href="#返回格式" aria-label="Permalink to &quot;返回格式&quot;">​</a></h2><p>默认不带 <code>type</code> 时，接口会直接跳转到随机文件地址。</p><p><code>type=url</code> 时返回文本链接。</p><p><code>type=json</code> 时返回文件信息，包括文件链接、文件 ID、文件名、文件类型、标签、分级等。</p><h2 id="访问限制" tabindex="-1">访问限制 <a class="header-anchor" href="#访问限制" aria-label="Permalink to &quot;访问限制&quot;">​</a></h2><p>随机图像 API 会遵守后台的公开访问规则：</p><table tabindex="0"><thead><tr><th>规则</th><th>效果</th></tr></thead><tbody><tr><td>目录限制</td><td>只能随机“目录”里允许的文件。</td></tr><tr><td>黑名单</td><td>黑名单文件不会进入随机池。</td></tr><tr><td>白名单模式</td><td>开启白名单模式后，只会返回允许公开访问的文件。</td></tr><tr><td>年龄分级</td><td>会按当前访问模式过滤 R12、R16、R18 等内容。</td></tr></tbody></table><p>如果筛选后没有可用文件，会返回没有匹配结果。</p><h2 id="缓存说明" tabindex="-1">缓存说明 <a class="header-anchor" href="#缓存说明" aria-label="Permalink to &quot;缓存说明&quot;">​</a></h2><p>随机图像 API 会缓存目录候选池，提高访问速度。</p><p>文件变化后系统会更新目录缓存版本，后续请求会重新生成候选池。空目录会短时间缓存，避免反复查询。</p><h2 id="访客图库" tabindex="-1">访客图库 <a class="header-anchor" href="#访客图库" aria-label="Permalink to &quot;访客图库&quot;">​</a></h2><p>访客图库用于开放一个只读的公开浏览页面，让访客查看你允许公开的目录。</p><p>开启后可以访问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/browse/目录名</span></span></code></pre></div><h2 id="访客图库设置" tabindex="-1">访客图库设置 <a class="header-anchor" href="#访客图库设置" aria-label="Permalink to &quot;访客图库设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>作用</th></tr></thead><tbody><tr><td>启用</td><td>开启或关闭访客图库。关闭后访客无法浏览。</td></tr><tr><td>图像加载模式</td><td>控制访客图库里图片预览使用原图还是缩略图。</td></tr><tr><td>开放目录</td><td>设置访客可以访问哪些目录。</td></tr></tbody></table><h2 id="图像加载模式" tabindex="-1">图像加载模式 <a class="header-anchor" href="#图像加载模式" aria-label="Permalink to &quot;图像加载模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>作用</th></tr></thead><tbody><tr><td>原图</td><td>访客页面直接加载原文件。</td></tr><tr><td>缩略图</td><td>访客页面优先加载缩略图，页面打开更快。</td></tr></tbody></table><h2 id="开放目录" tabindex="-1">开放目录 <a class="header-anchor" href="#开放目录" aria-label="Permalink to &quot;开放目录&quot;">​</a></h2><p>开放目录决定访客能看到哪些内容。</p><p>例如填写：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>访客就可以访问这些目录：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/browse/1</span></span>
<span class="line"><span>https://你的域名/browse/2</span></span>
<span class="line"><span>https://你的域名/browse/landscape</span></span>
<span class="line"><span>https://你的域名/browse/portrait</span></span></code></pre></div><p>也可以开放子目录，例如 <code>/2026/lucky/</code>。访客访问未开放的目录会被拒绝。</p><h2 id="访客图库能做什么" tabindex="-1">访客图库能做什么 <a class="header-anchor" href="#访客图库能做什么" aria-label="Permalink to &quot;访客图库能做什么&quot;">​</a></h2><p>访客图库支持：</p><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>浏览目录</td><td>查看开放目录里的文件和子目录。</td></tr><tr><td>搜索</td><td>按文件名、文件 ID、标签搜索。</td></tr><tr><td>类型筛选</td><td>筛选图片、视频、音频或其他文件。</td></tr><tr><td>标签筛选</td><td>包含指定标签或排除指定标签。</td></tr><tr><td>方向筛选</td><td>筛选横图或竖图。</td></tr><tr><td>时间筛选</td><td>按上传时间范围筛选。</td></tr><tr><td>扩展名筛选</td><td>按文件扩展名筛选。</td></tr><tr><td>复制链接</td><td>复制文件访问链接。</td></tr><tr><td>预览媒体</td><td>图片、视频、音频可在访客页查看或播放。</td></tr></tbody></table><h2 id="访客图库访问规则" tabindex="-1">访客图库访问规则 <a class="header-anchor" href="#访客图库访问规则" aria-label="Permalink to &quot;访客图库访问规则&quot;">​</a></h2><p>访客图库同样会遵守公开访问规则：</p><table tabindex="0"><thead><tr><th>规则</th><th>效果</th></tr></thead><tbody><tr><td>开放目录</td><td>只显示允许开放的目录。</td></tr><tr><td>访问模式</td><td>按当前年龄分级访问模式过滤内容。</td></tr><tr><td>白名单模式</td><td>开启后只显示允许公开访问的文件。</td></tr><tr><td>黑名单</td><td>黑名单文件不会显示。</td></tr></tbody></table>`,44)])])}const u=d(o,[["render",i]]);export{b as __pageData,u as default};
